def minPlatforms(arr, dep):
    n = len(arr)
    max_platforms = 0
    for i in range(n):
        count = 1
        for j in range(n):
            if i != j:
                if arr[j] < dep[i] and arr[i] < dep[j]:
                    count += 1
        max_platforms = max(max_platforms, count)
    return max_platforms

