def countOverlaps(starts, ends):
    i = j = 0
    current = maxCount = 0
    n = len(starts)
    while i < n and j < n:
        if starts[i] <= ends[j]:
            current += 1
            i += 1
        else:
            current -= 1
            j += 1
        maxCount = max(maxCount, current)
    return maxCount

def trackMaxOverlap(events):  # events sorted with type 'start' or 'end'
    count = maxCount = 0
    for time, type in events:
        if type == 'start':
            count += 1
        else:
            count -= 1
        maxCount = max(maxCount, count)
    return maxCount

