def compareAndAdvance(A, B, i, j):
    if i >= len(A) or j >= len(B):
        return None  # handle edge case
    if A[i] <= B[j]:
        # Process A[i]
        i += 1
        return 'A', i, j
    else:
        # Process B[j]
        j += 1
        return 'B', i, j
